@startuml
!theme plain

package "sandbox" as sandbox {
  package "design" as design {
    package "template" as template {
      class "App" as App {
        <<component>>
      }
      class "GeradorPropriedadesCriptografado" as GeradorPropriedadesCriptografado {
        <<component>>
      }
      class "GeradorXMLCompactado" as GeradorXMLCompactado {
        <<component>>
      }
      class "GeradorArquivo" as GeradorArquivo {
        <<actor>>
      }

      App ..> GeradorPropriedadesCriptografado : dependency
      App ..> GeradorXMLCompactado : dependency
      GeradorPropriedadesCriptografado --> GeradorArquivo : extends
      GeradorXMLCompactado --> GeradorArquivo : extends
    }
  }
}

@enduml
